import java.time.*;
public class DateArithmetic {
    public static void main(String[] args) {
        LocalDate d = LocalDate.of(2024, 1, 31);
        LocalDate next = d.plusMonths(1);
        System.out.println(next);
        LocalDate week = d.plusWeeks(1);
        System.out.println(week);
    }
